# tasksegment/models/baselines.pyfrom __future__ import annotationsimport torchimport torch.nn as nnimport torch.nn.functional as F# 如果没有安装，请 pip install segmentation_models_pytorchtry:    import segmentation_models_pytorch as smpexcept ImportError:    smp = None# 如果没有安装，请 pip install monaitry:    from monai.networks.nets import DynUNetexcept ImportError:    DynUNet = Noneclass BaseBaseline(nn.Module):    """基线模型统一接口适配器"""    def __init__(self, in_channels: int = 1, num_classes: int = 2):        super().__init__()        self.in_channels = in_channels        self.num_classes = num_classes    def forward(self, xs=None, ys=None, Ftext=None, xq=None):        if xq is None:            raise ValueError("xq (query image) must be provided for baselines")        logits = self.net(xq)        return {"pred_masks": logits}    def segment_with_task(self, xq=None, task_tokens=None, query_feats=None, output_size=None):        """适配 evaluation.py / inference.py 中的接口"""        out = self(xq)        logits = out["pred_masks"]        if output_size is not None and logits.shape[-2:] != output_size:            logits = F.interpolate(logits, size=output_size, mode="bilinear", align_corners=False)        return {"pred_masks": logits}    def encode_query(self, xq):        return xq  # 基线模型不需要金字塔特征，直接返回占位class StandardUNet(BaseBaseline):    """标准 2D UNet Baseline (使用 smp 库实现，无争议)"""    def __init__(self, in_channels=1, num_classes=2, base_dim=64):        super().__init__(in_channels, num_classes)        if smp is None:            raise ImportError("请安装 segmentation_models_pytorch: pip install segmentation_models_pytorch")        self.net = smp.Unet(            encoder_name="resnet34",            encoder_weights=None,  # 从头训练，公平对比            in_channels=in_channels,            classes=num_classes        )class UNetPlusPlus(BaseBaseline):    """UNet++ Baseline (依赖 smp 库)"""    def __init__(self, in_channels=1, num_classes=2, base_dim=64):        super().__init__(in_channels, num_classes)        if smp is None:            raise ImportError("请安装 segmentation_models_pytorch: pip install segmentation_models_pytorch")        self.net = smp.UnetPlusPlus(            encoder_name="resnet34",            encoder_weights=None,            in_channels=in_channels,            classes=num_classes        )class NNUNetLike(BaseBaseline):    """模拟 nnUNet 架构的 Baseline (依赖 monai 库的 DynUNet)"""    def __init__(self, in_channels=1, num_classes=2, base_dim=32):        super().__init__(in_channels, num_classes)        if DynUNet is None:            raise ImportError("请安装 monai: pip install monai")        kernels, strides = [3,3,3,3,3], [1,2,2,2,2]        self.net = DynUNet(            spatial_dims=2,            in_channels=in_channels,            out_channels=num_classes,            kernel_size=kernels,            strides=strides,            upsample_kernel_size=strides[1:],  # 适配新版 MONAI 参数名            filters=[base_dim, base_dim*2, base_dim*4, base_dim*8, base_dim*16],            norm_name="batch",            deep_supervision=False,            res_block=True        )